function getRealSI(dyeA, dyeB) {
  if (!dyeA || !dyeB || dyeA === dyeB) return null;
  const a = SI_DATA[dyeA];
  if (a && a[dyeB] !== undefined) return a[dyeB];
  const b = SI_DATA[dyeB];
  if (b && b[dyeA] !== undefined) return b[dyeA];
  return null;
}
function getRealSIR(dyeA, dyeB) {
  if (!dyeA || !dyeB || dyeA === dyeB) return null;
  const a = SIR_DATA[dyeA];
  return (a && a[dyeB] !== undefined) ? a[dyeB] : null;
}
function getRealSSM(dyeA, dyeB) {
  if (!dyeA || !dyeB || dyeA === dyeB) return null;
  const a = SSM_DATA[dyeA];
  return (a && a[dyeB] !== undefined) ? a[dyeB] : null;
}
function hasRealSI(dyeA, dyeB)  { return getRealSI(dyeA, dyeB)  !== null; }
